class Ping {
	constructor(request) {
		this.value = 100;
		this.array = new Array(Ping.LENGTH);
		this.array.fill(this.value);
		this.times = {};

		var id = 0;
		setInterval(() => {
			this.times[++id] = Date.now();
			request(id);
		}, 200);
	}
	check(id) {
        const time = this.times[id];
        if (!time) return;
        
	    const deltaTime = Date.now() - time;
	    this.value -= Ping.K * this.array.shift();
	    this.array.push(deltaTime);
	    this.value += Ping.K * deltaTime;
	    delete this.times[id];
	}
}
Ping.LENGTH = 4;
Ping.K = 1 / Ping.LENGTH;
class WebRTC {
	constructor(socket, doComplete, dataChannelSettings) {
        console.log('webrtc constructor');
		Object.assign(this, {
			remoteReceived: false,
			socket: socket,
			doComplete: doComplete,
			channels: {},
			dataChannelSettings: dataChannelSettings
		});
		this.doCreateDataChannels();
	}

	doHandleError(error) {
        console.log('doHandleError');
		throw error;
	}

	doWaitforDataChannels() {
        console.log('doWaitforDataChannels');
	}

	doCreateDataChannels() {
        console.log('doCreateDataChannels');
		const labels = Object.keys(this.dataChannelSettings);
		labels.forEach(label => {
            const channel = {onmessage: data => {}};
            channel.send = msg => this.socket.emit('webrtcMessage', {
                'label': label,
                'msg': msg
            });
            this.channels[label] = channel;
		});
        this.socket.on('webrtcMessage', data => {
            const {label, msg} = data;
            this.channels[label].onmessage({'data': msg});
        });
        waitFor( () => window.webRTC)
            .then(w => this.doComplete() );
	}
}


function waitFor(f, time=200) {
    return new Promise( (res, rej) => {
        const r = f();
        if (r) {
            res(r);
        } else {
            setTimeout( () => res( waitFor(f, time) ), time);
        }
    });
}
class Camera {
  constructor() {
    this.x1 = halfW - ship.x;
    this.y1 = halfH - ship.y;
    this.x = this.x1;
    this.y = this.y1;
  }
  
  update() {
    this.x1 -= halfW;
    this.y1 -= halfH;

    if (player.alife) {
      const spd = ship.speed, k = 0.5 * spd | 0 === 0 ? 0 : 0.1 / spd;

      this.x1 -= (ship.x + ship.speedX * w * k + this.x1) * 0.03 * dt;
      this.y1 -= (ship.y + ship.speedY * h * k + this.y1) * 0.03 * dt;
      
      this.x1 -= ship.speedX * dt;
      this.y1 -= ship.speedY * dt;
    }

    this.updateBackground();

    //this.x1 += halfW;
    //this.y1 += halfH;
    this.x = halfW - ship.x;//+= (this.x1 - this.x) * 0.3 * dt;
    this.y = halfH - ship.y;//+= (this.y1 - this.y) * 0.3 * dt;
  }
  
  updateBackground() {
    for (var i = 0, len = Universe.foregroundUniforms.length; i < len; i++) {
      const depth = Orb.station.depth + (1 - Orb.station.depth) * i / (Universe.FOREGROUND_COUNT - 1);

      Universe.foregroundUniforms[i]['pos'] = [
        this.x * depth,
        this.y * depth
      ]
    }

    Universe.backgroundUniforms['pos'] = [this.x * 0.075, this.y * 0.075];
  }

  lookAt(o) {
    this.x = this.x1 = halfW - o.x;
    this.y = this.y1 = halfH - o.y;
  }
}
class SpaceObject {
  constructor(texture, x, y, rotation, zIndex, spdX, spdY, cont) {
    this.sprite = new PIXI.Sprite(texture);
    this.sprite.anchor.set(0.5);
    
    Object.assign(this, {
      x: x || 0,
      y: y || 0,
      speedX: spdX || 0,
      speedY: spdX || 0,
      rotation: rotation || 0,
      drawX: -1000,
      drawY: -1000,
    });

    if (zIndex === undefined) {
      (cont || container).addChild(this.sprite);
    } else {
      (cont || container).addChildAt(this.sprite, zIndex);
    }
  }

  update() {
    this.updateDrawPosition();
    this.updatePosition();
  }

  updatePosition() {
    this.x += this.speedX * dt;
    this.y += this.speedY * dt;
  }

  updateRotation() {
    this.rotation += this.angleSpeed * dt;
    this.rotation = Math.ang(this.rotation);
  }

  updateDrawPosition() {
    this.drawX = this.x + camera.x;
    this.drawY = this.y + camera.y;
  }

  getDistance(o) {
    return Math.sqrt( this.getSqrDistance(o) );
  }

  getSqrDistance(o) {
    const dx = this.x - o.x, dy = this.y - o.y;
    return dx * dx + dy * dy;
  }

  getAngle(o) {
    return Math.atan2(o.y - this.y, o.x - this.x);
  }

  get drawX() {
    return this.sprite.x;
  }
  set drawX(value) {
    this.sprite.x = value;
  }

  get drawY() {
    return this.sprite.y;
  }
  set drawY(value) {
    this.sprite.y = value;
  }

  get rotation() {
    return this.sprite.rotation;
  }
  set rotation(value) {
    this.sprite.rotation = value;
  }

  get direction() {
    return Math.atan2(this.speedY, this.speedX);
  }

  get speed() {
    return Math.sqrt(this.sqrSpeed);
  }

  get sqrSpeed() {
    return this.speedX * this.speedX + this.speedY * this.speedY;
  }

}
class ItemGenerator {
	static createImage(ID, callback) {
		const width = 90, height = width;

		const canvas = document.createElement('canvas');
		const ctx = canvas.getContext('2d');

		canvas.width = width;
		canvas.height = height;

		setTimeout(ItemGenerator.drawImage, 0, ID, ctx, context => {
			const dataURL = context.canvas.toDataURL(); // produces a PNG file

			callback(dataURL);

			const prefix = Item.getCategory(ID).slice(0, 1);
			ldb.set(`_${prefix}_${ID}`, dataURL);
		});
	}

	static drawImage(ID, ctx, callback) {
		const category = Item.getCategory(ID);
		const data = ID.split('|');

		const seed = +ID.replaceAll(/\.|\|/, '');
		const subcategory = Item.getSubCategory(ID);
		const lvl = data[2];

		var I;
		if (subcategory === 'element') {
			Material.draw(seed, lvl, ctx, category, context => {
				callback(context);

				Material.catalog[ID] = true;
			});
			return;
		} else switch (category) {
			case 'weapon': I = Weapon; break;
			case 'engine': I = Engine; break;
			case 'other': I = Other; break;
		}

		I.draw(seed, subcategory, lvl, ctx, callback);
	}

}
class Item extends SpaceObject {
	constructor(pack) {
		const {'type': type, 'ID': ID, 'x': x, 'y': y} = pack;
		
		super(null, x, y);

		Item.getTexture(type, texture => this.sprite.texture = texture);

		this.type = type;
		this.angleSpeed = 0.1 * (Math.random() * 2 - 1);

		container.addChild(this.sprite);

		Item.list[ID] = this;
	}

	update() {
		super.update();
		this.updateRotation();
	}

	updatePosition() {}

	moveTo(ship) {
		const start = Date.now(), x0 = this.x, y0 = this.y;

		this.updatePosition = () => this.follow(start, x0, y0, ship);

		setTimeout(() => this.die(), Item.FOLLOW_TIME);
	}

	follow(start, x0, y0, ship) {
		const t = Date.now() - start;

		this.x = x0 + t / Item.FOLLOW_TIME * (ship.x - x0);
		this.y = y0 + t / Item.FOLLOW_TIME * (ship.y - y0);
	}

	die() {
		delete Item.list[this.ID];
		container.removeChild(this.sprite);
	}

	static getTexture(ID, callback) {
		Item.getSrc(ID, image => callback( PIXI.Texture.fromImage(image) ) );
	}

	static getSrc(ID, callback) {
		if (ID in Item.catalog) {
			callback(Item.catalog[ID].path);
		} else {
			Item.getImage(ID, callback);
		}
	}

	static getImage(ID, callback) {
		if (ID in images) { //get image from RAM
			callback(images[ID]);
		} else {
			const prefix = Item.getCategory(ID).slice(0, 1);

			ldb.get(`_${prefix}_${ID}`, value => {
				if (value === null) { //generate image and save it to the hard drive and RAM
					ItemGenerator.createImage(ID, image => { callback(image); Item.cacheImage(ID, image); } );
				} else { //get image from the hard drive
	 				callback(value);
	 				Item.cacheImage(ID, value);
	 				//ItemGenerator.createImage(ID, image => { callback(image); Item.cacheImage(ID, image); } );
				}
			});
		}
	}

	static cacheImage(ID, image) {
		images[ID] = image;
	}

	static getPrice(ID) {
		var k;
		switch ( Item.getCategory(ID) ) {
			case 'weapon':
			case 'engine':
			case 'other':
			k = 100;
			break;
			default: k = 10;
		}

		if (Item.getSubCategory(ID) === 'element') {
			k *= 0.5;
		}

		return Item.getLevel(ID) * k;
	}

	static getName(ID) {
		if (ID in Item.catalog) {
			return Item.catalog[ID].name
		}

		const info = Item.getCategory(ID);

		const firstWord = Item.getSubCategory(ID) === 'element' ? 'part of ' : 'unknown ';

		return firstWord + (info === 'other' ? 'equipment' : info);
	}

	static getDescription(ID) {
		return (Item.getName(ID) + '\nlevel: ' + Item.getLevel(ID) + '\n' + JSON.stringify( Item.getStats(ID) ) )
		.replaceAll(/{|}|"/, '')
		.replaceAll(',', '\n')
		.replaceAll(':', ': ');
	}

	static getStackSize(ID) {
		if (ID in Item.catalog) {//console.log(0);
			return Item.catalog[ID].stackSize;
		} else if ( Item.getCategory(ID) === 'material') {//console.log(1);
			return 16;
		}
//console.log(2);
		return 1;
	}

	static compatible(ID, compartment) {
		if (compartment in Item.forAll) {
			return true;
		}

		if (Item.getSubCategory(ID) === 'element') {
			return false;
		}

		if (ID in Item.catalog) {
			for (var i = 0, len = Item.catalog[ID].compartments.length; i < len; i++) {
				if (Item.catalog[ID].compartments[i] === compartment) {
					return true;
				}
			}
		}

		switch ( Item.getCategory(ID) ) {
			case 'weapon': return compartment === 'weapons';
			case 'engine': return compartment === 'engines';
			case 'other': return compartment === 'other';
		}

		return false;
	}

	static getCategory(ID) {
		if (ID in Item.catalog) {
			return Item.catalog[ID].category;
		}

		return Item.categories[ ID.split('|')[0] ][0];
	}

	static getSubCategory(ID) {
		if (ID in Item.catalog) {
			return Item.catalog[ID].subcategory;
		}

		const data = ID.split('|');

		if (!Item.categories[ data[0] ]) {
			return 'unknown';
		}

		return Item.categories[ data[0] ][1][ data[1] ] || 'element';
	}

	static getLevel(ID) {
		if (ID in Item.catalog) {
			return Item.catalog[ID].level;
		}

		return +ID.split('|')[2];
	}

	static getStats(ID) {
		var values;

		if (ID in Item.catalog) {
			values = Item.catalog[ID].stats;
		} else {
			values = ID.split('|').slice(3);
		}

		if (values.length === 0) {
			return {};
		}

		const category = Item.getCategory(ID);
		const subcategory = Item.getSubCategory(ID);
		const keys = Item.stats[category][subcategory];

		return Object.assign( ...keys.map( (v, i) => ( { [v]: +values[i] } ) ) );
	}

	static checkEquipment(ID) {
		if (Item.getSubCategory(ID) === 'element') {
			return;
		}

		switch ( Item.getCategory(ID) ) {
			case 'weapon': Weapon.check(ID); break;
			case 'engine': Engine.check(ID); break;
			case 'other': Other.check(ID); break;
		}
	}

	static clearEquipment() {
		Item.delEquipment(Weapon);
		Item.delEquipment(Engine);
		Item.delEquipment(Other);
	}

	static delEquipment(Equipment) {
		for (var ID in Equipment.catalog) {
			if (Equipment.catalog[ID] === Equipment.default) {
				continue;
			}

			var toDelete = true;
			const predicate = item => item && item['type'] === ID;

			if (
				Interface.inventory.find(predicate) ||
				Interface.crafting.find(predicate) ||
				Interface.result.find(predicate) ||
				Interface.hand.find(predicate)
			) {
				toDelete = false;
				continue;
			}
			
			for (var j in Controller.list) {
				const player = Controller.list[j], ship = player.body;

				if (!ship || !(ship instanceof SpaceShip)) {
					continue;	
				}

				if (
					ship.weapons.find(predicate) ||
					ship.engines.find(predicate) ||
					ship.other.find(predicate) 
				) {
					toDelete = false;
					break;
				}
			}

			if (toDelete) {
				if (Equipment === Weapon ) {
					const weapon = Weapon.catalog[ID];
					if (weapon instanceof MovingShotWpn) {
						weapon.delBulletImage();
					}
				}

				delete Equipment.catalog[ID];
			}
		}
	}

	static delImages() {
		const dBOpenRequest = window.indexedDB.open('d2', 1);
		
		dBOpenRequest.onsuccess = event => {
			const db = dBOpenRequest.result;

			db.transaction('s', 'readwrite').objectStore('s').getAll().onsuccess = event => {
				const result = event.target.result || null;

				for (var i = 0, len = result.length; i < len; i++) {
					const row = result[i];
					const prefix = row['k'].slice(1, 2);
					const ID = row['k'].slice(3);

					if ( row['k'].slice(0, 1) === '_' && row['k'].slice(2, 3) === '_' ) {
						if ( Item.getSubCategory(ID) !== 'element' )
						switch (prefix) {
							case 'w': Item.delImage(Weapon, ID, db); break;
							case 'e': Item.delImage(Engine, ID, db); break;
							case 'o': Item.delImage(Other, ID, db); break;
							case 'b': Item.delImage(Bullet, ID, db); break;
						}
					}
				}
			};
		};
	}

	static delImage(Equipment, ID, db) {
		var toDelete = true;
		for (var id in Equipment.catalog) {
			if (id === ID) {
				toDelete = false;
				return;
			}
		}

		if (toDelete) {
			const prefix = Equipment === Bullet ? 'b' : Item.getCategory(ID).slice(0, 1);
			db.transaction('s', 'readwrite').objectStore('s').delete(`_${prefix}_${ID}`);

			delete images[ID];
		}
	}

	static update() {
		for (var i in Item.list) {
			Item.list[i].update();
		}
	}
}
